document.getElementById('year').textContent=new Date().getFullYear();
const observer=new IntersectionObserver(entries=>entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add('show');observer.unobserve(entry.target)}}),{threshold:.08});
document.querySelectorAll('.reveal').forEach(el=>observer.observe(el));
const dialog=document.getElementById('lightbox');
const dialogImage=document.getElementById('lightboxImage');
const dialogTitle=document.getElementById('lightboxTitle');
document.querySelectorAll('.zoomable').forEach(button=>button.addEventListener('click',()=>{dialogImage.src=button.dataset.full;dialogImage.alt=button.querySelector('img')?.alt||button.dataset.title||'Product image';dialogTitle.textContent=button.dataset.title||'Product image';dialog.showModal()}));
document.querySelector('.close').addEventListener('click',()=>dialog.close());
dialog.addEventListener('click',event=>{if(event.target===dialog)dialog.close()});
document.getElementById('brief').addEventListener('submit',event=>{event.preventDefault();const value=id=>document.getElementById(id).value.trim();const subject=`Tin Tech manufacturing inquiry — ${value('company')||'New project'}`;const body=`Hello George,\n\nI would like Tin Tech Packaging to review a manufacturing project.\n\nName: ${value('name')}\nCompany: ${value('company')}\nEmail: ${value('email')}\nProject type: ${value('type')}\nEstimated quantity: ${value('qty')||'To be discussed'}\nDelivery destination: ${value('destination')||'To be discussed'}\n\nProject details:\n${value('details')}\n\nPlease advise the next information required.\n`;location.href=`mailto:hockeyundergroundusa@gmail.com?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`});
